import { isAbsent, isDefined } from "@opendaw/lib-std";
export class Events {
    static subscribe(eventTarget, type, listener, options) {
        eventTarget.addEventListener(type, listener, options);
        return { terminate: () => eventTarget.removeEventListener(type, listener, options) };
    }
    static subscribeAny(eventTarget, type, listener, options) {
        eventTarget.addEventListener(type, listener, options);
        return { terminate: () => eventTarget.removeEventListener(type, listener, options) };
    }
    static DOUBLE_DOWN_THRESHOLD = 200;
    static subscribeDblDwn = (eventTarget, listener) => {
        let lastDownTime = 0.0;
        return this.subscribe(eventTarget, "pointerdown", event => {
            const now = performance.now();
            if (now - lastDownTime < this.DOUBLE_DOWN_THRESHOLD) {
                event.preventDefault();
                event.stopImmediatePropagation();
                listener(event);
            }
            lastDownTime = now;
        }, { capture: true });
    };
    static subscribeDblUp = (eventTarget, listener) => {
        let lastDownTime = 0.0;
        return this.subscribe(eventTarget, "pointerup", event => {
            const now = performance.now();
            if (now - lastDownTime < this.DOUBLE_DOWN_THRESHOLD) {
                event.preventDefault();
                event.stopImmediatePropagation();
                listener(event);
            }
            lastDownTime = now;
        }, { capture: true });
    };
    static PreventDefault = event => event.preventDefault();
    static isTextInput = (target) => {
        return target instanceof HTMLInputElement
            || target instanceof HTMLTextAreaElement
            || (target instanceof HTMLElement && isDefined(target.getAttribute("contenteditable")));
    };
    /**
     * Detects keyboard events triggered by browser autofill (e.g., Safari).
     * Autofill events often have empty or missing key/code properties.
     */
    static isAutofillEvent(event) {
        return isAbsent(event.key) || event.key === ""
            || event.key === "Unidentified" || isAbsent(event.code) || event.code === "";
    }
}
